module sync_down_counter(
    input reset_clk,
    input sync_reset,
    input enable,
    output reg [3:0] count_out
);

    always @(posedge reset_clk) begin
        if (sync_reset)
            count_out <= 4'b1111;
        else if (enable)
            count_out <= count_out - 1;
    end

endmodule
